     5→import { useNavExpansionStore } from '../stores/useNavExpansionStore';
     6→import { useThemeStore } from '../stores/useThemeStore';
     7→import { PageSettingsPanel } from './PageSettingsPanel';
     8→import { TimeTrackingPanel } from './TimeTrackingPanel';
     9→import { useNavigate } from 'react-router-dom';
    10→import { useSettingsStore } from '../stores/useSettingsStore';
    11→import { DndContext, closestCenter, PointerSensor, useSensor, useSensors } from '@dnd-kit/core';
    12→import type { DragEndEvent } from '@dnd-kit/core';
    13→import { SortableContext, verticalListSortingStrategy, useSortable, arrayMove } from '@dnd-kit/sortable';
    14→import { CSS } from '@dnd-kit/utilities';
    15→
    16→/**
    17→ * FOUNDATIONAL: NavItem interface with expandable support
    18→ * Any nav item can have sub-pages by adding `children`.
    19→ */
    20→interface NavItem {
    21→  icon: string;
    22→  label: string;
    23→  path: string;
    24→  shortcut?: string;
    25→  hasSettings?: boolean; // Whether this page has custom settings
    26→  children?: NavItem[]; // Sub-pages (expandable)
    27→  defaultExpanded?: boolean; // Initial expansion state
    28→}
    29→
    30→// Fixed navigation items (always at top, not draggable)
    31→const fixedNavigation: NavItem[] = [
    32→  {
    33→    icon: '🏠',
    34→    label: 'Dashboard',
    35→    path: '/',
    36→    shortcut: 'D',
    37→    hasSettings: true,
    38→    defaultExpanded: true,
    39→    children: [
    40→      { icon: '🔗', label: 'Link Library', path: '/links' },
    41→    ],
    42→  },
    43→];
    44→
    45→// Draggable navigation items (user can reorganize)
    46→const draggableNavigation: NavItem[] = [
    47→  {
    48→    icon: '📅',
    49→    label: 'Schedule',
    50→    path: '/schedule',
    51→    shortcut: 'P',
    52→    hasSettings: false,
    53→    defaultExpanded: false,
    54→    children: [
    55→      { icon: '⏱️', label: 'Timer', path: '/schedule?tab=timer' },
    56→      { icon: '📋', label: 'Entries', path: '/schedule?tab=entries' },
    57→      { icon: '📊', label: 'Summary', path: '/schedule?tab=summary' },
    58→      { icon: '📆', label: 'Calendar', path: '/schedule?tab=calendar' },
    59→      { icon: '📁', label: 'Projects', path: '/schedule?tab=projects' },
    60→    ],
    61→  },
    62→  {
    63→    icon: '📝',
    64→    label: 'Notes',
    65→    path: '/notes',
    66→    shortcut: 'N',
    67→    hasSettings: false,
    68→    defaultExpanded: false,
    69→    children: [
    70→      { icon: '📅', label: 'Daily Notes', path: '/notes?daily=true' },
    71→      { icon: '🕸️', label: 'Graph', path: '/graph' },
    72→      { icon: '📊', label: 'Diagrams', path: '/diagrams' },
    73→      { icon: '📋', label: 'Forms', path: '/forms' },
    74→    ],
    75→  },
    76→  { icon: '✓', label: 'Tasks', path: '/tasks', shortcut: 'T', hasSettings: false },
    77→];
    78→
    79→// Sortable Navigation Item Component
    80→interface SortableNavItemProps {
    81→  item: NavItem;
    82→  isCollapsed: boolean;
    83→  isActive: boolean;
    84→  onPageSettings: (e: React.MouseEvent, path: string) => void;
    85→  isDisablingClicks: boolean;
    86→}
    87→
    88→const SortableNavItem: React.FC<SortableNavItemProps> = ({ item, isCollapsed, isActive, onPageSettings, isDisablingClicks }) => {
    89→  const {
    90→    attributes,
    91→    listeners,
    92→    setNodeRef,
    93→    transform,
    94→    transition,
    95→    isDragging,
    96→  } = useSortable({ id: item.path });
    97→
    98→  const location = useLocation();
    99→  const { isExpanded, toggleExpanded } = useNavExpansionStore();
   100→  const hasChildren = item.children && item.children.length > 0;
   101→  const expanded = isExpanded(item.path);
   102→
   103→  const style = {
   104→    transform: CSS.Transform.toString(transform),
   105→    transition,
   106→    opacity: isDragging ? 0.5 : 1,
   107→  };
   108→
   109→  // Check if any child is active
   110→  const isChildActive = (navItem: NavItem) => {
   111→    if (!navItem.children) return false;
   112→    return navItem.children.some((child) => {
   113→      // Handle paths with query params
   114→      if (child.path.includes('?')) {
   115→        const [pathname, query] = child.path.split('?');
   116→        if (location.pathname !== pathname) return false;
   117→        const params = new URLSearchParams(query);
   118→        const currentParams = new URLSearchParams(location.search);
   119→        for (const [key, value] of params.entries()) {
   120→          if (currentParams.get(key) !== value) return false;
   121→        }
   122→        return true;
   123→      }
   124→      return location.pathname === child.path;
   125→    });
   126→  };
   127→
   128→  const childActive = isChildActive(item);
   129→
   130→  return (
   131→    <li ref={setNodeRef} style={{...style, pointerEvents: isDisablingClicks ? 'none' : 'auto'}} {...attributes}>
   132→      <Link
   133→        to={item.path}
   134→        onClick={(e) => {
   135→          if (isDisablingClicks) {
   136→            e.preventDefault();
   137→            return false;
   138→          }
   139→        }}
   140→        className={`
   141→          flex items-center gap-3 px-3 h-10 rounded-button
   142→          transition-all duration-standard ease-smooth
   143→          relative group
   144→          ${
   145→            isActive || childActive
   146→              ? 'bg-surface-light-elevated dark:bg-surface-dark-elevated text-text-light-primary dark:text-text-dark-primary'
   147→              : 'text-text-light-secondary dark:text-text-dark-secondary hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated'
   148→          }
   149→        `}
   150→        title={isCollapsed ? item.label : undefined}
   151→      >
   152→        {/* Active indicator (left accent) */}
   153→        {isActive && (
   154→          <div className="absolute left-0 top-2 bottom-2 w-[3px] bg-accent-blue rounded-r" />
   155→        )}
   156→
   157→        {/* Icon - Fixed 20px size - DRAG HANDLE */}
   158→        <span
   159→          {...listeners}
   160→          className="w-5 h-5 flex items-center justify-center flex-shrink-0 text-lg cursor-grab active:cursor-grabbing"
   161→          role="button"
   162→          aria-label={`Drag ${item.label} to reorder`}
   163→          tabIndex={0}
   164→        >
   165→          {item.icon}
   166→        </span>
   167→
   168→        {/* Label (hidden when collapsed) */}
   169→        {!isCollapsed && (
   170→          <>
   171→            <span className="flex-1 text-base leading-5 font-medium truncate">
   172→              {item.label}
   173→            </span>
   174→
   175→            {/* Page Settings Icon (shown on hover) */}
   176→            {item.hasSettings && (
   177→              <button
   178→                onClick={(e) => onPageSettings(e, item.path)}
   179→                className="
   180→                  opacity-0 group-hover:opacity-100
   181→                  w-5 h-5 flex items-center justify-center flex-shrink-0
   182→                  text-text-light-secondary dark:text-text-dark-secondary
   183→                  hover:text-text-light-primary dark:hover:text-text-dark-primary
   184→                  transition-opacity duration-200
   185→                "
   186→                title="Page Settings"
   187→                aria-label={`${item.label} page settings`}
   188→              >
   189→                <span className="text-sm">⚙</span>
   190→              </button>
   191→            )}
   192→
   193→            {/* Expand/Collapse Chevron (for items with children) */}
   194→            {hasChildren && (
   195→              <button
   196→                onClick={(e) => {
   197→                  e.preventDefault();
   198→                  e.stopPropagation();
   199→                  toggleExpanded(item.path);
   200→                }}
   201→                className="
   202→                  w-5 h-5 flex items-center justify-center flex-shrink-0
   203→                  text-text-light-secondary dark:text-text-dark-secondary
   204→                  hover:text-text-light-primary dark:hover:text-text-dark-primary
   205→                  transition-transform duration-200
   206→                "
   207→                title={expanded ? 'Collapse' : 'Expand'}
   208→              >
   209→                <span
   210→                  className={`text-xs transition-transform duration-200 ${
   211→                    expanded ? 'rotate-90' : ''
   212→                  }`}
   213→                >
   214→                  ▶
   215→                </span>
   216→              </button>
   217→            )}
   218→          </>
   219→        )}
   220→
   221→        {/* Tooltip for collapsed state */}
   222→        {isCollapsed && (
   223→          <div className="
   224→            absolute left-full ml-2 px-2 py-1
   225→            bg-surface-light-elevated dark:bg-surface-dark-elevated
   226→            text-text-light-primary dark:text-text-dark-primary text-xs rounded
   227→            opacity-0 group-hover:opacity-100
   228→            pointer-events-none transition-opacity duration-200
   229→            whitespace-nowrap z-50
   230→          ">
   231→            {item.label}
   232→          </div>
   233→        )}
   234→      </Link>
   235→
   236→      {/* Children (Sub-pages) - only show when expanded and not collapsed */}
   237→      {hasChildren && expanded && !isCollapsed && (
   238→        <ul className="ml-6 mt-1 space-y-1">
   239→          {item.children!.map((child) => (
   240→            <li key={child.path}>
   241→              <Link
   242→                to={child.path}
   243→                className={`
   244→                  flex items-center gap-3 px-3 h-9 rounded-button
   245→                  transition-all duration-standard ease-smooth
   246→                  relative group
   247→                  ${
   248→                    location.pathname === child.path
   249→                      ? 'bg-surface-light-elevated dark:bg-surface-dark-elevated text-text-light-primary dark:text-text-dark-primary'
   250→                      : 'text-text-light-secondary dark:text-text-dark-secondary hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated'
   251→                  }
   252→                `}
   253→              >
   254→                {/* Active indicator (left accent) */}
   255→                {location.pathname === child.path && (
   256→                  <div className="absolute left-0 top-1.5 bottom-1.5 w-[3px] bg-accent-blue rounded-r" />
   257→                )}
   258→
   259→                {/* Icon */}
   260→                <span className="w-4 h-4 flex items-center justify-center flex-shrink-0 text-sm">
   261→                  {child.icon}
   262→                </span>
   263→
   264→                {/* Label */}
   265→                <span className="flex-1 text-sm leading-5 font-medium truncate">
   266→                  {child.label}
   267→                </span>
   268→              </Link>
   269→            </li>
   270→          ))}
   271→        </ul>
   272→      )}
   273→    </li>
   274→  );
   275→};
   276→
   277→export const Sidebar: React.FC = () => {
   278→  const { isCollapsed, toggleCollapse, isMobileMenuOpen, setMobileMenuOpen } = useSidebarStore();
   279→  const { mode, toggleTheme } = useThemeStore();
   280→  const navOrder = useSidebarNavStore((state) => state.navOrder);
   281→  const setNavOrder = useSidebarNavStore((state) => state.setNavOrder);
   282→  const { isExpanded, toggleExpanded } = useNavExpansionStore();
   283→  const location = useLocation();
   284→  const [pageSettingsOpen, setPageSettingsOpen] = useState<string | null>(null);
   285→  const [isDisablingClicks, setIsDisablingClicks] = useState(false);
   286→  const disableTimeoutRef = useRef<NodeJS.Timeout | null>(null);
   287→  const navigate = useNavigate();
   288→  const dailyNotesEnabled = useSettingsStore((state) => state.dailyNotes.enabled);
   289→
   290→  // Check if a nav path is active (handles both pathname and query params)
   291→  const isActive = (path: string) => {
   292→    // Handle paths with query params (e.g., /schedule?tab=calendar)
   293→    if (path.includes('?')) {
   294→      const [pathname, query] = path.split('?');
   295→      if (location.pathname !== pathname) return false;
   296→      const params = new URLSearchParams(query);
   297→      const currentParams = new URLSearchParams(location.search);
   298→      // Check if all specified params match
   299→      for (const [key, value] of params.entries()) {
   300→        if (currentParams.get(key) !== value) return false;
   301→      }
   302→      return true;
   303→    }
   304→    // Simple pathname match
   305→    return location.pathname === path;
   306→  };
   307→
   308→  // Check if any child of a parent is active (for highlighting parent when child is active)
   309→  const isChildActive = (item: NavItem) => {
   310→    if (!item.children) return false;
   311→    return item.children.some((child) => isActive(child.path));
   312→  };
   313→
   314→  // Configure drag sensors (require 5px movement to start dragging)
   315→  const sensors = useSensors(
   316→    useSensor(PointerSensor, {
   317→      activationConstraint: {
   318→        distance: 5,
   319→      },
   320→    })
   321→  );
   322→
   323→  // Sort draggable navigation items by saved order
   324→  const sortedDraggableNavigation = [...draggableNavigation].sort((a, b) => {
   325→    const aIndex = navOrder.indexOf(a.path);
   326→    const bIndex = navOrder.indexOf(b.path);
   327→    // If path not found in order, put it at the end
   328→    return (aIndex === -1 ? 999 : aIndex) - (bIndex === -1 ? 999 : bIndex);
   329→  });
   330→
   331→  const handleDragStart = () => {
   332→    // Clear any existing timeout to prevent race conditions
   333→    if (disableTimeoutRef.current) {
   334→      clearTimeout(disableTimeoutRef.current);
   335→    }
   336→
   337→    setIsDisablingClicks(true);
   338→  };
   339→
   340→  const handleDragEnd = (event: DragEndEvent) => {
   341→    const { active, over } = event;
   342→
   343→    if (over && active.id !== over.id) {
   344→      const oldIndex = navOrder.indexOf(active.id as string);
   345→      const newIndex = navOrder.indexOf(over.id as string);
   346→
   347→      if (oldIndex !== -1 && newIndex !== -1) {
   348→        const newOrder = arrayMove(navOrder, oldIndex, newIndex);
   349→        setNavOrder(newOrder);
   350→      }
   351→    }
   352→
   353→    // Re-enable clicks after a delay to prevent accidental navigation
   354→    // Store timeout ID in ref so it survives re-renders
   355→    disableTimeoutRef.current = setTimeout(() => {
   356→      setIsDisablingClicks(false);
   357→      disableTimeoutRef.current = null;
   358→    }, 150);
   359→  };
   360→
   361→  // Cleanup timeout on unmount
   362→  useEffect(() => {
   363→    return () => {
   364→      if (disableTimeoutRef.current) {
   365→        clearTimeout(disableTimeoutRef.current);
   366→      }
   367→    };
   368→  }, []);
   369→
   370→  const handlePageSettings = (e: React.MouseEvent, path: string) => {
   371→    e.preventDefault();
   372→    e.stopPropagation();
   373→    setPageSettingsOpen(path);
   374→  };
   375→
   376→  // Close mobile menu on route change
   377→  useEffect(() => {
   378→    setMobileMenuOpen(false);
   379→  }, [location.pathname, setMobileMenuOpen]);
   380→
   381→  // Handler for Ctrl+D keyboard shortcut (Daily Notes)
   382→  const handleTodayClick = () => {
   383→    navigate('/notes?daily=true');
   384→  };
   385→
   386→  // Keyboard shortcut: Cmd/Ctrl + B to toggle sidebar
   387→  useEffect(() => {
   388→    const handleKeyDown = (e: KeyboardEvent) => {
   389→      if ((e.metaKey || e.ctrlKey) && e.key === 'b') {
   390→        e.preventDefault();
   391→        toggleCollapse();
   392→      }
   393→    };
   394→
   395→    window.addEventListener('keydown', handleKeyDown);
   396→    return () => window.removeEventListener('keydown', handleKeyDown);
   397→  }, [toggleCollapse]);
   398→
   399→  // Keyboard shortcut: Cmd/Ctrl + D to open today's daily note
   400→  useEffect(() => {
   401→    const handleKeyDown = (e: KeyboardEvent) => {
   402→      if ((e.metaKey || e.ctrlKey) && e.key === 'd' && dailyNotesEnabled) {
   403→        e.preventDefault();
   404→        handleTodayClick();
   405→      }
   406→    };
   407→
   408→    window.addEventListener('keydown', handleKeyDown);
   409→    return () => window.removeEventListener('keydown', handleKeyDown);
   410→  }, [dailyNotesEnabled, handleTodayClick]);
   411→
   412→  return (
   413→    <>
   414→      {/* Mobile backdrop */}
   415→      {isMobileMenuOpen && (
   416→        <div
   417→          className="lg:hidden fixed inset-0 bg-black/50 z-30"
   418→          onClick={() => setMobileMenuOpen(false)}
   419→        />
   420→      )}
   421→
   422→      {/* Sidebar */}
   423→      <aside
   424→        aria-label="Main navigation sidebar"
   425→        className={`
   426→          fixed left-0 top-0 h-screen
   427→          bg-surface-light-elevated dark:bg-surface-dark
   428→          border-r border-border-light dark:border-border-dark
   429→          transition-all duration-200 ease-in-out
   430→          flex flex-col
   431→          z-40
   432→          ${isCollapsed ? 'w-[60px]' : 'w-[210px]'}
   433→
   434→          ${/* Mobile: slide in/out as drawer */ ''}
   435→          lg:translate-x-0
   436→          ${isMobileMenuOpen ? 'translate-x-0' : '-translate-x-full lg:translate-x-0'}
   437→        `}
   438→      >
   439→      {/* Logo Section */}
   440→      <div className="p-4 border-b border-border-light dark:border-border-dark">
   441→        <Link
   442→          to="/"
   443→          className="flex items-center gap-3 overflow-hidden"
   444→        >
   445→          <img
   446→            src="/images/logos/nb3.png"
   447→            alt="Neuman Brain"
   448→            className="w-8 h-8 flex-shrink-0 rounded-button"
   449→          />
   450→          {!isCollapsed && (
   451→            <div className="flex flex-col min-w-0">
   452→              <h1 className="text-sm font-semibold text-text-light-primary dark:text-text-dark-primary truncate">
   453→                NEUMAN BRAIN
   454→              </h1>
   455→              <p className="text-xs text-text-light-secondary dark:text-text-dark-secondary truncate">
   456→                Management Platform
   457→              </p>
   458→            </div>
   459→          )}
   460→        </Link>
   461→      </div>
   462→
   463→      {/* Navigation Items */}
   464→      <nav aria-label="Primary navigation" className="flex-1 overflow-y-auto py-4">
   465→        <ul className="space-y-1 px-2">
   466→          {/* Fixed Navigation Items (Dashboard - not draggable, supports children) */}
   467→          {fixedNavigation.map((item) => {
   468→            const hasChildren = item.children && item.children.length > 0;
   469→            const expanded = isExpanded(item.path);
   470→            const parentActive = isActive(item.path);
   471→            const childActive = isChildActive(item);
   472→
   473→            return (
   474→              <li key={item.path}>
   475→                {/* Parent Item */}
   476→                <div className="flex items-center">
   477→                  <Link
   478→                    to={item.path}
   479→                    className={`
   480→                      flex-1 flex items-center gap-3 px-3 h-10 rounded-button
   481→                      transition-all duration-standard ease-smooth
   482→                      relative group
   483→                      ${
   484→                        parentActive || childActive
   485→                          ? 'bg-surface-light-elevated dark:bg-surface-dark-elevated text-text-light-primary dark:text-text-dark-primary'
   486→                          : 'text-text-light-secondary dark:text-text-dark-secondary hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated'
   487→                      }
   488→                    `}
   489→                    title={isCollapsed ? item.label : undefined}
   490→                  >
   491→                    {/* Active indicator (left accent) */}
   492→                    {parentActive && (
   493→                      <div className="absolute left-0 top-2 bottom-2 w-[3px] bg-accent-blue rounded-r" />
   494→                    )}
   495→
   496→                    {/* Icon - Fixed 20px size */}
   497→                    <span className="w-5 h-5 flex items-center justify-center flex-shrink-0 text-lg">
   498→                      {item.icon}
   499→                    </span>
   500→
   501→                    {/* Label (hidden when collapsed) */}
   502→                    {!isCollapsed && (
   503→                      <>
   504→                        <span className="flex-1 text-base leading-5 font-medium truncate">
   505→                          {item.label}
   506→                        </span>
   507→
   508→                        {/* Page Settings Icon (shown on hover) */}
   509→                        {item.hasSettings && (
   510→                          <button
   511→                            onClick={(e) => handlePageSettings(e, item.path)}
   512→                            className="
   513→                              opacity-0 group-hover:opacity-100
   514→                              w-5 h-5 flex items-center justify-center flex-shrink-0
   515→                              text-text-light-secondary dark:text-text-dark-secondary
   516→                              hover:text-text-light-primary dark:hover:text-text-dark-primary
   517→                              transition-opacity duration-200
   518→                            "
   519→                            title="Page Settings"
   520→                          >
   521→                            <span className="text-sm">⚙</span>
   522→                          </button>
   523→                        )}
   524→
   525→                        {/* Expand/Collapse Chevron (for items with children) */}
   526→                        {hasChildren && (
   527→                          <button
   528→                            onClick={(e) => {
   529→                              e.preventDefault();
   530→                              e.stopPropagation();
   531→                              toggleExpanded(item.path);
   532→                            }}
   533→                            className="
   534→                              w-5 h-5 flex items-center justify-center flex-shrink-0
   535→                              text-text-light-secondary dark:text-text-dark-secondary
   536→                              hover:text-text-light-primary dark:hover:text-text-dark-primary
   537→                              transition-transform duration-200
   538→                            "
   539→                            title={expanded ? 'Collapse' : 'Expand'}
   540→                          >
   541→                            <span
   542→                              className={`text-xs transition-transform duration-200 ${
   543→                                expanded ? 'rotate-90' : ''
   544→                              }`}
   545→                            >
   546→                              ▶
   547→                            </span>
   548→                          </button>
   549→                        )}
   550→                      </>
   551→                    )}
   552→
   553→                    {/* Tooltip for collapsed state */}
   554→                    {isCollapsed && (
   555→                      <div className="
   556→                        absolute left-full ml-2 px-2 py-1
   557→                        bg-surface-light-elevated dark:bg-surface-dark-elevated
   558→                        text-text-light-primary dark:text-text-dark-primary text-xs rounded
   559→                        opacity-0 group-hover:opacity-100
   560→                        pointer-events-none transition-opacity duration-200
   561→                        whitespace-nowrap z-50
   562→                      ">
   563→                        {item.label}
   564→                      </div>
   565→                    )}
   566→                  </Link>
   567→                </div>
   568→
   569→                {/* Children (Sub-pages) - only show when expanded and not collapsed */}
   570→                {hasChildren && expanded && !isCollapsed && (
   571→                  <ul className="ml-6 mt-1 space-y-1">
   572→                    {item.children!.map((child) => (
   573→                      <li key={child.path}>
   574→                        <Link
   575→                          to={child.path}
   576→                          className={`
   577→                            flex items-center gap-3 px-3 h-9 rounded-button
   578→                            transition-all duration-standard ease-smooth
   579→                            relative group
   580→                            ${
   581→                              isActive(child.path)
   582→                                ? 'bg-surface-light-elevated dark:bg-surface-dark-elevated text-text-light-primary dark:text-text-dark-primary'
   583→                                : 'text-text-light-secondary dark:text-text-dark-secondary hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated'
   584→                            }
   585→                          `}
   586→                        >
   587→                          {/* Active indicator (left accent) */}
   588→                          {isActive(child.path) && (
   589→                            <div className="absolute left-0 top-1.5 bottom-1.5 w-[3px] bg-accent-blue rounded-r" />
   590→                          )}
   591→
   592→                          {/* Icon */}
   593→                          <span className="w-4 h-4 flex items-center justify-center flex-shrink-0 text-sm">
   594→                            {child.icon}
   595→                          </span>
   596→
   597→                          {/* Label */}
   598→                          <span className="flex-1 text-sm leading-5 font-medium truncate">
   599→                            {child.label}
   600→                          </span>
   601→                        </Link>
   602→                      </li>
   603→                    ))}
   604→                  </ul>
   605→                )}
   606→              </li>
   607→            );
   608→          })}
   609→
   610→          {/* Draggable Navigation Items (Notes, Planning, Tasks) */}
   611→          <DndContext
   612→            sensors={sensors}
   613→            collisionDetection={closestCenter}
   614→            onDragStart={handleDragStart}
   615→            onDragEnd={handleDragEnd}
   616→          >
   617→            <SortableContext items={navOrder} strategy={verticalListSortingStrategy}>
   618→              {sortedDraggableNavigation.map((item) => (
   619→                <SortableNavItem
   620→                  key={item.path}
   621→                  item={item}
   622→                  isCollapsed={isCollapsed}
   623→                  isActive={isActive(item.path)}
   624→                  onPageSettings={handlePageSettings}
   625→                  isDisablingClicks={isDisablingClicks}
   626→                />
   627→              ))}
   628→            </SortableContext>
   629→          </DndContext>
   630→        </ul>
   631→      </nav>
   632→
   633→      {/* Time Tracking Panel - only visible when expanded */}
   634→      {!isCollapsed && <TimeTrackingPanel />}
   635→
   636→      {/* Bottom Section */}
   637→      <div className="border-t border-border-light dark:border-border-dark p-2 space-y-1">
   638→        {/* Settings (Fixed) */}
   639→        <Link
   640→          to="/settings"
   641→          className={`
   642→            w-full flex items-center gap-3 px-3 h-10 rounded-button
   643→            ${isActive('/settings')
   644→              ? 'bg-surface-light-elevated dark:bg-surface-dark-elevated text-text-light-primary dark:text-text-dark-primary'
   645→              : 'text-text-light-secondary dark:text-text-dark-secondary hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated'
   646→            }
   647→            transition-all duration-standard ease-smooth
   648→            group relative
   649→          `}
   650→          title={isCollapsed ? 'Settings' : undefined}
   651→        >
   652→          {/* Active indicator (left accent) */}
   653→          {isActive('/settings') && (
   654→            <div className="absolute left-0 top-2 bottom-2 w-[3px] bg-accent-blue rounded-r" />
   655→          )}
   656→
   657→          <span className="w-5 h-5 flex items-center justify-center flex-shrink-0 text-lg">⚙️</span>
   658→          {!isCollapsed && (
   659→            <span className="flex-1 text-base leading-5 font-medium text-left truncate">
   660→              Settings
   661→            </span>
   662→          )}
   663→          {isCollapsed && (
   664→            <div className="
   665→              absolute left-full ml-2 px-2 py-1
   666→              bg-surface-dark text-text-dark-primary text-xs rounded
   667→              opacity-0 group-hover:opacity-100
   668→              pointer-events-none transition-opacity duration-200
   669→              whitespace-nowrap z-50
   670→            ">
   671→              Settings
   672→            </div>
   673→          )}
   674→        </Link>
   675→
   676→        {/* Theme Toggle */}
   677→        <button
   678→          onClick={toggleTheme}
   679→          className={`
   680→            w-full flex items-center gap-3 px-3 h-10 rounded-button
   681→            text-text-light-secondary dark:text-text-dark-secondary
   682→            hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated
   683→            transition-all duration-standard ease-smooth
   684→            group relative
   685→          `}
   686→          title={isCollapsed ? (mode === 'dark' ? 'Light Mode' : 'Dark Mode') : undefined}
   687→        >
   688→          <span className="w-5 h-5 flex items-center justify-center flex-shrink-0 text-lg">
   689→            {mode === 'dark' ? '☀️' : '🌙'}
   690→          </span>
   691→          {!isCollapsed && (
   692→            <span className="flex-1 text-base leading-5 font-medium text-left">
   693→              {mode === 'dark' ? 'Light Mode' : 'Dark Mode'}
   694→            </span>
   695→          )}
   696→          {isCollapsed && (
   697→            <div className="
   698→              absolute left-full ml-2 px-2 py-1
   699→              bg-surface-dark text-text-dark-primary text-xs rounded
   700→              opacity-0 group-hover:opacity-100
   701→              pointer-events-none transition-opacity duration-200
   702→              whitespace-nowrap z-50
   703→            ">
   704→              {mode === 'dark' ? 'Light Mode' : 'Dark Mode'}
   705→            </div>
   706→          )}
   707→        </button>
   708→
   709→        {/* Collapse Toggle */}
   710→        <button
   711→          onClick={toggleCollapse}
   712→          className={`
   713→            w-full flex items-center gap-3 px-3 h-10 rounded-button
   714→            text-text-light-secondary dark:text-text-dark-secondary
   715→            hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated
   716→            transition-all duration-standard ease-smooth
   717→            group relative
   718→          `}
   719→          title={isCollapsed ? 'Expand Sidebar' : undefined}
   720→        >
   721→          <span className="w-5 h-5 flex items-center justify-center flex-shrink-0 text-lg">
   722→            {isCollapsed ? '▶' : '◀'}
   723→          </span>
   724→          {!isCollapsed && (
   725→            <span className="flex-1 text-base leading-5 font-medium text-left">
   726→              Collapse
   727→            </span>
   728→          )}
   729→          {isCollapsed && (
   730→            <div className="
   731→              absolute left-full ml-2 px-2 py-1
   732→              bg-surface-dark text-text-dark-primary text-xs rounded
   733→              opacity-0 group-hover:opacity-100
   734→              pointer-events-none transition-opacity duration-200
   735→              whitespace-nowrap z-50
   736→            ">
   737→              Expand Sidebar
   738→            </div>
   739→          )}
   740→        </button>
   741→      </div>
   742→    </aside>
   743→
   744→    {/* Page Settings Panel */}
   745→    {pageSettingsOpen && (
   746→      <PageSettingsPanel
   747→        isOpen={true}
   748→        onClose={() => setPageSettingsOpen(null)}
   749→        pagePath={pageSettingsOpen}
   750→      />
   751→    )}
   752→    </>
   753→  );
   754→};
