    17→
    18→export function FieldList({
    19→  fields,
    20→  onEdit,
    21→  onDelete,
    22→  onDuplicate,
    23→  onMoveUp,
    24→  onMoveDown,
    25→}: FieldListProps) {
    26→  const sortedFields = [...fields].sort((a, b) => a.order - b.order);
    27→
    28→  if (fields.length === 0) {
    29→    return (
    30→      <div className="flex flex-col items-center justify-center p-8 text-center border-2 border-dashed border-border-light dark:border-border-dark rounded-lg">
    31→        <p className="text-text-light-secondary dark:text-text-dark-secondary">
