    33→        </p>
    34→      </div>
    35→    );
    36→  }
    37→
    38→  return (
    39→    <div className="space-y-2">
    40→      {sortedFields.map((field, index) => (
    41→        <FieldListItem
    42→          key={field.id}
    43→          field={field}
    44→          isFirst={index === 0}
    45→          isLast={index === sortedFields.length - 1}
    46→          onEdit={() => onEdit(field)}
    47→          onDelete={() => onDelete(field.id)}
    48→          onDuplicate={() => onDuplicate(field)}
    49→          onMoveUp={() => onMoveUp(field.id)}
    50→          onMoveDown={() => onMoveDown(field.id)}
    51→        />
    52→      ))}
    53→    </div>
    54→  );
    55→}
    56→
    57→interface FieldListItemProps {
    58→  field: FormField;
    59→  isFirst: boolean;
    60→  isLast: boolean;
    61→  onEdit: () => void;
    62→  onDelete: () => void;
    63→  onDuplicate: () => void;
    64→  onMoveUp: () => void;
    65→  onMoveDown: () => void;
    66→}
    67→
    68→function FieldListItem({
    69→  field,
    70→  isFirst,
    71→  isLast,
    72→  onEdit,
    73→  onDelete,
    74→  onDuplicate,
    75→  onMoveUp,
    76→  onMoveDown,
    77→}: FieldListItemProps) {
    78→  const getFieldTypeLabel = (type: string): string => {
    79→    const labels: Record<string, string> = {
    80→      text: 'Text',
    81→      textarea: 'Text Area',
    82→      number: 'Number',
    83→      date: 'Date',
    84→      time: 'Time',
    85→      select: 'Select',
    86→      multiselect: 'Multi-Select',
    87→      radio: 'Radio',
    88→      checkbox: 'Checkbox',
