   108→          {field.required && (
   109→            <span className="text-xs px-1.5 py-0.5 bg-red-500/10 text-red-500 rounded">
   110→              Required
   111→            </span>
   112→          )}
   113→        </div>
   114→        <div className="flex items-center gap-2 text-xs text-text-light-secondary dark:text-text-dark-secondary mt-1">
