   117→          </span>
   118→          {field.description && (
   119→            <span className="truncate">{field.description}</span>
   120→          )}
   121→        </div>
   122→      </div>
   123→
   124→      {/* Actions */}
   125→      <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
   126→        {/* Move Up/Down */}
   127→        <button
   128→          onClick={onMoveUp}
